            if is_near_ground and in_air:
                logger.debug(
                    f"Near-ground override in_air to False: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # 兜底：高度足够高（<-5.0m）也认定在空中（安全而保守的阈值）
            if not in_air and z < -5.0:
                in_air = True

            # 再次确保极近地面不被认为在空中
            if in_air and abs(z) < 0.10:
                logger.debug(
                    f"Final override in_air to False due to very near ground: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # 修复：当高度接近地面（例如碰撞导致 z≈-2m）且 landed_state 表示已落地时，
            # 以 landed_state 为准，将 in_air 置为 False，避免“在空中但高度异常低”的误判。
            if in_air and is_near_ground and landed in (0, 1):
                if (self._landed_mapping_flipped and landed == 1) or (
                    not self._landed_mapping_flipped and landed == 0
                ):
                    logger.debug(
                        f"Override in_air to False based on landed_state on near-ground: "
                        f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                    )
                    in_air = False

