"""
airsim_adapter.py
AirSim SimpleFlight 仿真适配器（纯 socket 版，无 tornado/asyncio 依赖）。
"""

import math
import logging
import base64
from typing import Optional

from adapters.sim_adapter import (
    SimAdapter, Position, GPSPosition, VehicleState, ActionResult,
)

logger = logging.getLogger(__name__)


class AirSimAdapter(SimAdapter):
    """AirSim SimpleFlight 适配器，纯 socket RPC，兼容任意 event loop。"""

    name = "airsim_simpleflight"
    description = "AirSim SimpleFlight via pure-socket msgpack-rpc (no tornado dependency)"
    supported_vehicles = ["multirotor"]

    def __init__(self, vehicle_name: str = ""):
        self._vehicle_name = vehicle_name
        self._client = None
        self._connected = False
        self._home_position: Optional[Position] = None
        # 记录是否检测到 landed_state 语义翻转：True 时 0=Flying,1=Landed
        self._landed_mapping_flipped: Optional[bool] = None

    # ── 连接 ──────────────────────────────────────────────────────────

    def connect(self, connection_str: str = "", timeout: float = 15.0) -> bool:
        ip, port = "127.0.0.1", 41451
        if connection_str:
            parts = connection_str.split(":")
            ip = parts[0]
            if len(parts) > 1:
                port = int(parts[1])

        logger.info(f"Connecting to AirSim: {ip}:{port} (pure-socket RPC)")
        try:
            from adapters.airsim_rpc import AirSimDirectClient
            self._client = AirSimDirectClient(ip, port, timeout=timeout)
            if not self._client.connect():
                raise ConnectionError(f"Cannot connect to {ip}:{port}")
            if not self._client.ping():
                raise ConnectionError("ping failed")
            self._client.enable_api_control(True, self._vehicle_name)
            self._client.arm_disarm(True, self._vehicle_name)
            self._connected = True
            # 记录起飞原点
            pos = self._get_position_raw()
            if pos:
                self._home_position = pos
            # 重置映射检测状态
            self._landed_mapping_flipped = None
            logger.info(f"✅ AirSim connected: {ip}:{port}, vehicles={self._client.list_vehicles()}")
            return True
        except Exception as e:
            logger.error(f"❌ AirSim connect error: {e}")
            self._connected = False
            return False

    def disconnect(self) -> None:
        if self._client:
            self._client.close()
        self._connected = False

    # ── 状态读取 ──────────────────────────────────────────────────────

    @property
    def is_connected(self) -> bool:
        return self._connected

    def _get_position_raw(self) -> Optional[Position]:
        try:
            state = self._client.get_multirotor_state(self._vehicle_name)
            kin = state.get("kinematics_estimated", {})
            pos = kin.get("position", {})
            return Position(
                north=pos.get("x_val", 0.0),
                east=pos.get("y_val", 0.0),
                down=pos.get("z_val", 0.0),
            )
        except Exception:
            return None

    def get_state(self) -> Optional[VehicleState]:
        if not self._connected:
            return None
        try:
            raw = self._client.get_multirotor_state(self._vehicle_name)
            kin = raw.get("kinematics_estimated", {})
            pos = kin.get("position", {})
            vel = kin.get("linear_velocity", {})
            landed = raw.get("landed_state", 0)

            # NED 坐标系：z<0 为在空中，接近 0 为落地
            z = pos.get("z_val", 0.0)

            # 高度阈值：|z|<0.25 认为接近地面，<-0.5 认为明显在空中
            is_near_ground = abs(z) < 0.25
            is_clearly_air = z < -0.5

            # 标准 AirSim 文档：0=Landed, 1=Flying
            in_air_std = False
            if landed in (0, 1):
                in_air_std = (landed == 1)

            # ── 修正 landed_state 映射检测逻辑 ─────────────────────
            # 首次检测 landed_state 是否翻转：True 表示 0=Flying,1=Landed
            if landed in (0, 1) and self._landed_mapping_flipped is None:
                # 如果高度明显在空中但 landed==0（标准语义下 0=Landed），
                # 或者高度接近地面但 landed==1（标准语义下 1=Flying），
                # 则判断枚举语义发生翻转（0=Flying,1=Landed）。
                if is_clearly_air and landed == 0:
                    self._landed_mapping_flipped = True
                    logger.info(
                        f"Detected flipped landed_state mapping: "
                        f"raw={landed}, z={z:.2f} (interpreting 0=Flying,1=Landed)"
                    )
                elif is_near_ground and landed == 1:
                    self._landed_mapping_flipped = True
                    logger.info(
                        f"Detected flipped landed_state mapping (ground but flying): "
                        f"raw={landed}, z={z:.2f} (interpreting 0=Flying,1=Landed)"
                    )
                else:
                    self._landed_mapping_flipped = False
                    logger.info(
                        f"Detected standard landed_state mapping: "
                        f"raw={landed}, z={z:.2f} (interpreting 0=Landed,1=Flying)"
                    )

            # 根据已确认的枚举语义重新解释
            if landed in (0, 1):
                if self._landed_mapping_flipped:
                    # 翻转语义：0=Flying,1=Landed
                    in_air_std = (landed == 0)
                else:
                    # 标准语义：0=Landed,1=Flying
                    in_air_std = (landed == 1)

            # 基于（可能翻转后的）枚举给出初始 in_air
            in_air = in_air_std if landed in (0, 1) else False

            # ── 兼容性与安全性逻辑 ──────────────────────────────────
            # 极近地面（|z|<0.10）一律视为落地
            if abs(z) < 0.10:
                in_air = False

            # 接近地面则倾向判定为落地
            if is_near_ground and in_air:
                logger.debug(
                    f"Near-ground override in_air to False: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # 兜底：高度足够高（<-5.0m）也认定在空中（安全而保守的阈值）
            if not in_air and z < -5.0:
                in_air = True

            # 再次确保极近地面不被认为在空中
            if in_air and abs(z) < 0.10:
                logger.debug(
                    f"Final override in_air to False due to very near ground: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # 修复：当高度接近地面（例如碰撞导致 z≈-2m）且 landed_state 表示已落地时，
            # 以 landed_state 为准，将 in_air 置为 False，避免“在空中但高度异常低”的误判。
            if in_air and is_near_ground and landed in (0, 1):
                if (self._landed_mapping_flipped and landed == 1) or (
                    not self._landed_mapping_flipped and landed == 0
                ):
                    logger.debug(
                        f"Override in_air to False based on landed_state on near-ground: "
                        f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                    )
                    in_air = False

            # ---- 关键修复：当高度不高(例如 -2m) 且 landed_state 显示已落地时，强制认为不在空中 ----
            # 失败案例：报告 is_in_air()=True 且高度约 -2.26m，疑似映射或判定异常。
            # 这里加入一个更宽松的“低空”阈值，例如 |z| < 3m
            if in_air and landed in (0, 1):
                low_altitude = abs(z) < 3.0
                if low_altitude:
                    # 标准语义：0=Landed,1=Flying；翻转语义：0=Flying,1=Landed
                    landed_meaning_landed = (
                        (self._landed_mapping_flipped is False and landed == 0)
                        or (self._landed_mapping_flipped is True and landed == 1)
                    )
                    if landed_meaning_landed:
                        logger.debug(
                            f"Override in_air to False due to low altitude with landed_state==LANDED: "
                            f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                        )
                        in_air = False

            # 再次兜底：如果仍然认为在空中，但高度非常低（例如 |z|<0.5），也倾向认为已落地，
            # 避免出现 “is_in_air=True 且 z≈-0.x~-2.x” 的异常组合。
            if in_air and abs(z) < 0.5 and landed in (0, 1):
                landed_meaning_landed_final = (
                    (self._landed_mapping_flipped is False and landed == 0)
                    or (self._landed_mapping_flipped is True and landed == 1)
                )
                if landed_meaning_landed_final:
                    logger.debug(
                        f"Final low-altitude override in_air to False: "
                        f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                    )
                    in_air = False

            # 进一步修复：如果检测到 landed_state 语义翻转（0=Flying,1=Landed），
            # 且高度不高（例如 |z| < 3m）但 landed==1（语义为“已落地”），
            # 则无条件认为不在空中，避免 “映射翻转 + 低空” 场景下的误判。
            if in_air and self._landed_mapping_flipped and landed == 1 and abs(z) < 3.0:
                logger.debug(
                    f"Flipped-mapping low-altitude override in_air to False: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # —— 额外修复：利用高度直接辅助判断，避免 landed_state 映射反时长期误判 ——
            # 当高度明显在空中且 landed_state 表示“落地”，强制认为在空中；
            # 当高度明显接近地面且 landed_state 表示“落地”，强制认为不在空中。
            if landed in (0, 1):
                if self._landed_mapping_flipped:
                    # 翻转语义：0=Flying,1=Landed
                    if landed == 1:
                        # 语义为“落地”
                        if is_clearly_air:
                            in_air = True
                        elif is_near_ground:
