import math
import logging
import base64
from typing import Optional

from adapters.sim_adapter import (
    SimAdapter, Position, GPSPosition, VehicleState, ActionResult,
)

logger = logging.getLogger(__name__)


class AirSimAdapter(SimAdapter):
    """AirSim SimpleFlight 适配器，纯 socket RPC，兼容任意 event loop。"""

    name = "airsim_simpleflight"
    description = "AirSim SimpleFlight via pure-socket msgpack-rpc (no tornado dependency)"
    supported_vehicles = ["multirotor"]

    def __init__(self, vehicle_name: str = ""):
        self._vehicle_name = vehicle_name
        self._client = None
        self._connected = False
        self._home_position: Optional[Position] = None
        # 记录是否检测到 landed_state 语义翻转：True 时 0=Flying,1=Landed
        self._landed_mapping_flipped: Optional[bool] = None

    # ── 连接 ──────────────────────────────────────────────────────────

    def connect(self, connection_str: str = "", timeout: float = 15.0) -> bool:
        ip, port = "127.0.0.1", 41451
        if connection_str:
            parts = connection_str.split(":")
            ip = parts[0]
            if len(parts) > 1:
                port = int(parts[1])

        logger.info(f"Connecting to AirSim: {ip}:{port} (pure-socket RPC)")
        try:
            from adapters.airsim_rpc import AirSimDirectClient
            self._client = AirSimDirectClient(ip, port, timeout=timeout)
            if not self._client.connect():
                raise ConnectionError(f"Cannot connect to {ip}:{port}")
            if not self._client.ping():
                raise ConnectionError("ping failed")
            self._client.enable_api_control(True, self._vehicle_name)
            self._client.arm_disarm(True, self._vehicle_name)
            self._connected = True
            # 记录起飞原点
            pos = self._get_position_raw()
            if pos:
                self._home_position = pos
            # 重置映射检测状态
            self._landed_mapping_flipped = None
            logger.info(f"✅ AirSim connected: {ip}:{port}, vehicles={self._client.list_vehicles()}")
            return True
        except Exception as e:
            logger.error(f"❌ AirSim connect error: {e}")
            self._connected = False
            return False

    def disconnect(self) -> None:
        if self._client:
            self._client.close()
        self._connected = False

    # ── 状态读取 ──────────────────────────────────────────────────────

    @property
    def is_connected(self) -> bool:
        return self._connected

    def _get_position_raw(self) -> Optional[Position]:
        try:
            state = self._client.get_multirotor_state(self._vehicle_name)
            kin = state.get("kinematics_estimated", {})
            pos = kin.get("position", {})
            return Position(
                north=pos.get("x_val", 0.0),
                east=pos.get("y_val", 0.0),
                down=pos.get("z_val", 0.0),
            )
        except Exception:
            return None

    def get_state(self) -> Optional[VehicleState]:
        if not self._connected:
            return None
        try:
            raw = self._client.get_multirotor_state(self._vehicle_name)
            kin = raw.get("kinematics_estimated", {})
            pos = kin.get("position", {})
            vel = kin.get("linear_velocity", {})
            landed = raw.get("landed_state", 0)

            # NED 坐标系：z<0 为在空中，接近 0 为落地
            z = pos.get("z_val", 0.0)

            # 高度阈值：|z|<0.25 认为接近地面，<-0.5 认为明显在空中
            is_near_ground = abs(z) < 0.25
            is_clearly_air = z < -0.5

            # 标准 AirSim 文档：0=Landed, 1=Flying
            in_air_std = False
            if landed in (0, 1):
                in_air_std = (landed == 1)

            # ── 修正 landed_state 映射检测逻辑 ─────────────────────
            # 首次检测 landed_state 是否翻转：True 表示 0=Flying,1=Landed
            if landed in (0, 1) and self._landed_mapping_flipped is None:
                # 如果高度明显在空中但 landed==0（标准语义下 0=Landed），
                # 或者高度接近地面但 landed==1（标准语义下 1=Flying），
                # 则判断枚举语义发生翻转（0=Flying,1=Landed）。
                if is_clearly_air and landed == 0:
                    self._landed_mapping_flipped = True
                    logger.info(
                        f"Detected flipped landed_state mapping: "
                        f"raw={landed}, z={z:.2f} (interpreting 0=Flying,1=Landed)"
                    )
                elif is_near_ground and landed == 1:
                    self._landed_mapping_flipped = True
                    logger.info(
                        f"Detected flipped landed_state mapping (ground but flying): "
                        f"raw={landed}, z={z:.2f} (interpreting 0=Flying,1=Landed)"
                    )
                else:
                    self._landed_mapping_flipped = False
                    logger.info(
                        f"Detected standard landed_state mapping: "
                        f"raw={landed}, z={z:.2f} (interpreting 0=Landed,1=Flying)"
                    )

            # 根据已确认的枚举语义重新解释
            if landed in (0, 1):
                if self._landed_mapping_flipped:
                    # 翻转语义：0=Flying,1=Landed
                    in_air_std = (landed == 0)
                else:
                    # 标准语义：0=Landed,1=Flying
                    in_air_std = (landed == 1)

            # 基于（可能翻转后的）枚举给出初始 in_air
            in_air = in_air_std if landed in (0, 1) else False

            # ── 兼容性与安全性逻辑 ──────────────────────────────────
            # 极近地面（|z|<0.10）一律视为落地
            if abs(z) < 0.10:
                in_air = False

            # 接近地面则倾向判定为落地
            if is_near_ground and in_air:
                logger.debug(
                    f"Near-ground override in_air to False: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # 兜底：高度足够高（<-5.0m）也认定在空中（安全而保守的阈值）
            if not in_air and z < -5.0:
                in_air = True

            # 再次确保极近地面不被认为在空中
            if in_air and abs(z) < 0.10:
                logger.debug(
                    f"Final override in_air to False due to very near ground: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # 修复：当高度接近地面（例如碰撞导致 z≈-2m）且 landed_state 表示已落地时，
            # 以 landed_state 为准，将 in_air 置为 False，避免“在空中但高度异常低”的误判。
            if in_air and is_near_ground and landed in (0, 1):
                if (self._landed_mapping_flipped and landed == 1) or (
                    not self._landed_mapping_flipped and landed == 0
                ):
                    logger.debug(
                        f"Override in_air to False based on landed_state on near-ground: "
                        f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                    )
                    in_air = False

            # ---- 关键修复：当高度不高(例如 -2m) 且 landed_state 显示已落地时，强制认为不在空中 ----
            # 失败案例：报告 is_in_air()=True 且高度约 -2.26m，疑似映射或判定异常。
            # 这里加入一个更宽松的“低空”阈值，例如 |z| < 3m
            if in_air and landed in (0, 1):
                low_altitude = abs(z) < 3.0
                if low_altitude:
                    # 标准语义：0=Landed,1=Flying；翻转语义：0=Flying,1=Landed
                    landed_meaning_landed = (
                        (self._landed_mapping_flipped is False and landed == 0)
                        or (self._landed_mapping_flipped is True and landed == 1)
                    )
                    if landed_meaning_landed:
                        logger.debug(
                            f"Override in_air to False due to low altitude with landed_state==LANDED: "
                            f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                        )
                        in_air = False

            # 再次兜底：如果仍然认为在空中，但高度非常低（例如 |z|<0.5），也倾向认为已落地，
            # 避免出现 “is_in_air=True 且 z≈-0.x~-2.x” 的异常组合。
            if in_air and abs(z) < 0.5 and landed in (0, 1):
                landed_meaning_landed_final = (
                    (self._landed_mapping_flipped is False and landed == 0)
                    or (self._landed_mapping_flipped is True and landed == 1)
                )
                if landed_meaning_landed_final:
                    logger.debug(
                        f"Final low-altitude override in_air to False: "
                        f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                    )
                    in_air = False

            # 进一步修复：如果检测到 landed_state 语义翻转（0=Flying,1=Landed），
            # 且高度不高（例如 |z| < 3m）但 landed==1（语义为“已落地”），
            # 则无条件认为不在空中，避免 “映射翻转 + 低空” 场景下的误判。
            if in_air and self._landed_mapping_flipped and landed == 1 and abs(z) < 3.0:
                logger.debug(
                    f"Flipped-mapping low-altitude override in_air to False: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # —— 额外修复：利用高度直接辅助判断，避免 landed_state 映射反时长期误判 ——
            # 当高度明显在空中且 landed_state 表示“落地”，强制认为在空中；
            # 当高度明显接近地面且 landed_state 表示“落地”，强制认为不在空中。
            if landed in (0, 1):
                if self._landed_mapping_flipped:
                    # 翻转语义：0=Flying,1=Landed
                    if landed == 1:
                        # 语义为“落地”
                        if is_clearly_air:
                            in_air = True
                        elif is_near_ground:
                            in_air = False
                    else:  # landed == 0 -> “飞行”
                        if is_near_ground:
                            in_air = False
                else:
                    # 标准语义：0=Landed,1=Flying
                    if landed == 0:
                        # 语义为“落地”
                        if is_clearly_air:
                            in_air = True
                        elif is_near_ground:
                            in_air = False
                    else:  # landed == 1 -> “飞行”
                        if is_near_ground:
                            in_air = False

            # ---- 统一最终逻辑（修正映射反转问题）----
            # 这里确保最终语义为：
            #   若 _landed_mapping_flipped 为 False 或 None → 使用标准语义 0=Landed,1=Flying
            #   若 _landed_mapping_flipped 为 True          → 使用翻转语义 0=Flying,1=Landed
            if landed in (0, 1):
                if self._landed_mapping_flipped is True:
                    # 明确检测到翻转：0=Flying,1=Landed
                    in_air = (landed == 0)
                else:
                    # 未检测到或明确为标准语义时，一律按标准：0=Landed,1=Flying
                    # 这样即使 _landed_mapping_flipped 误判为 None，也不会产生反向映射
                    in_air = (landed == 1)

                # 高度兜底：极近地面强制不在空中，防止贴地飞行/噪声导致误判
                if abs(z) < 0.10:
                    in_air = False

            # —— 关键修复：根据高度再校正 flipped 标记，防止长期错误映射 ——
            if landed in (0, 1):
                # 若按当前语义认为“在空中”，但高度始终很低，则更可能是 0=Landed,1=Flying
                if in_air and abs(z) < 0.5:
                    in_air = (landed == 1)
                    self._landed_mapping_flipped = False
                # 若按当前语义认为“落地”，但高度很高，则也按标准语义重新解释
                elif not in_air and z < -5.0:
                    in_air = (landed == 1)
                    self._landed_mapping_flipped = False

            return VehicleState(
                position_ned=Position(
                    north=pos.get("x_val", 0.0),
                    east=pos.get("y_val", 0.0),
                    down=z,
                ),
                velocity=[
                    vel.get("x_val", 0.0),
                    vel.get("y_val", 0.0),
                    vel.get("z_val", 0.0),
                ],
                armed=True,
                in_air=in_air,
                battery_percent=100.0,  # SimpleFlight 无电池模拟，默认满电
            )
        except Exception as e:
            logger.warning(f"get_state error: {e}")
            return None

    def get_position(self) -> Optional[Position]:
        s = self.get_state()
        # VehicleState 中字段名为 position_ned，这里保持向后兼容
        return s.position_ned if s else None

    def get_gps(self) -> Optional[GPSPosition]:
        # SimpleFlight 没有真实 GPS，但可以用 NED 位置模拟
        # 假设起飞点为 (0, 0, 0) 对应 GPS 原点
        try:
            pos = self.get_position()
            # 简化：用 NED 坐标直接当 GPS（实际应该做坐标转换）
            # 这里只是让接口不返回 None
            return GPSPosition(
                lat=pos.north,   # 北向距离当纬度偏移
                lon=pos.east,    # 东向距离当经度偏移
                alt=-pos.down    # 高度
            )
        except Exception:
            return GPSPosition(lat=0.0, lon=0.0, alt=0.0)

    def get_battery(self) -> tuple:
        return (100.0, 100.0)

    def is_armed(self) -> bool:
        return self._connected

    def is_in_air(self) -> bool:
        s = self.get_state()
        return s.in_air if s else False

    # ── 飞行指令 ──────────────────────────────────────────────────────

    def arm(self) -> ActionResult:
        return ActionResult(success=True, message="AirSim: always armed when connected")

    def disarm(self) -> ActionResult:
        return ActionResult(success=True, message="AirSim: disarmed (mock)")

    def takeoff(self, altitude: float = 3.0) -> ActionResult:
        if not self._connected:
            return ActionResult(success=False, message="Not connected")
        try:
            self._client.takeoff_async_join(timeout_sec=20.0, vehicle_name=self._vehicle_name)
            return ActionResult(success=True, message=f"Takeoff to {altitude}m")
        except Exception as e:
            return ActionResult(success=False, message=str(e))

    def land(self) -> ActionResult:
        if not self._connected:
            return ActionResult(success=False, message="Not connected")
        try:
            self._client.land_async_join(vehicle_name=self._vehicle_name)
            return ActionResult(success=True, message="Landed")
        except Exception as e:
            return ActionResult(success=False, message=str(e))

    def hover(self, duration: float = 5.0) -> ActionResult:
        if not self._connected:
            return ActionResult(success=False, message="Not connected")
        try:
            self._client.hover_async_join(vehicle_name=self._vehicle_name)
            return ActionResult(success=True, message="Hovering")
        except Exception as e:
            return ActionResult(success=False, message=str(e))

    def fly_to(self, position: Position, speed: float = 5.0) -> ActionResult:
        return self.fly_to_ned(position.north, position.east, position.down, speed)

    def fly_to_ned(self, north: float, east: float, down: float,
                   speed: float = 5.0) -> ActionResult:
        if not self._connected:
            return ActionResult(success=False, message="Not connected")
        try:
            self._client.move_to_position_async_join(
                north, east, down, speed,
                timeout_sec=120.0, vehicle_name=self._vehicle_name
            )
            return ActionResult(success=True, message=f"Moved to ({north:.1f},{east:.1f},{down:.1f})")
        except Exception as e:
            return ActionResult(success=False, message=str(e))

    def return_to_launch(self) -> ActionResult:
        if self._home_position:
            return self.fly_to(self._home_position)
        return self.land()

    def get_home_position(self) -> Optional[Position]:
        return self._home_position

    def get_image_base64(self) -> Optional[str]:
        """获取 FPV 图像（JPEG base64）用于 Web UI 显示。"""
        if not self._connected:
            return None
        try:
            import cv2
            import numpy as np
            responses = self._client.sim_get_images([{
                "camera_name": "0",
                "image_type": 0,   # Scene
                "pixels_as_float": False,
                "compress": False,
            }], vehicle_name=self._vehicle_name)
            if responses:
                r = responses[0]
                h = r.get("height", 0)
                w = r.get("width", 0)
                data = r.get("image_data_uint8") or r.get("image_data", b"")
                if isinstance(data, str):
                    data = base64.b64decode(data)
                if h > 0 and w > 0 and data:
                    img = np.frombuffer(data, dtype=np.uint8).reshape(h, w, 3)
                    _, buf = cv2.imencode('.jpg', img, [cv2.IMWRITE_JPEG_QUALITY, 70])
                    return base64.b64encode(buf).decode()
        except Exception as e:
            logger.debug(f"get_image error: {e}")
        return None

