                    )

            # 根据已确认的枚举语义重新解释
            if landed in (0, 1):
                if self._landed_mapping_flipped:
                    # 翻转语义：0=Flying,1=Landed
                    in_air_std = (landed == 0)
                else:
                    # 标准语义：0=Landed,1=Flying
                    in_air_std = (landed == 1)

            # 基于（可能翻转后的）枚举给出初始 in_air
            in_air = in_air_std if landed in (0, 1) else False

            # ── 兼容性与安全性逻辑 ──────────────────────────────────
            # 极近地面（|z|<0.10）一律视为落地
            if abs(z) < 0.10:
                in_air = False

            # 接近地面则倾向判定为落地
            if is_near_ground and in_air:
                logger.debug(
                    f"Near-ground override in_air to False: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
                in_air = False

            # 兜底：高度足够高（<-5.0m）也认定在空中（安全而保守的阈值）
            if not in_air and z < -5.0:
                in_air = True

            # 再次确保极近地面不被认为在空中
            if in_air and abs(z) < 0.10:
                logger.debug(
                    f"Final override in_air to False due to very near ground: "
                    f"z={z:.2f}, landed={landed}, flipped={self._landed_mapping_flipped}"
                )
